/**
 * Team Service
 * 
 * Manages team creation, updates, deletion, and member management for business
 * accounts. Handles team menu access permissions and team member operations
 * including adding and retrieving team members.
 */

import { apiRequest } from '@/shared/services/apiClient.js';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import logger from '@/shared/utils/logger.js';

const _teamService = {
  async createTeam(businessId, teamData) {
    logger.debug('Creating team', { teamData, businessId });
    if (!businessId || !String(businessId).trim()) {throw new Error('Business ID is required');}
    if (!teamData || !teamData.name || !String(teamData.name).trim()) {throw new Error('Team name is required');}
    if (!Array.isArray(teamData.menus) || teamData.menus.length === 0) {throw new Error('At least one menu is required');}

    const body = { name: String(teamData.name).trim(), menus: teamData.menus };

    const res = await apiRequest(`/api/team/${businessId}/create`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });

    if (res && (res.code === '01' || res.code === '00')) {return res.data || res;}
    if (res && Object.keys(res).length === 0) {return {};}
    throw new Error((res && res.message) || 'Failed to create team');
  },

  async getTeams(businessId) {
    if (!businessId || !String(businessId).trim()) {throw new Error('Business ID is required');}

    logger.debug('Fetching teams for business', { businessId });
    const res = await apiRequest(`/api/team/${businessId}`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
    });

    logger.debug('getTeams response', { 
      response: res, 
      code: res?.code, 
      data: res?.data, 
      isArray: Array.isArray(res?.data),
      dataLength: res?.data?.length 
    });

    if (res && (res.code === '00' || res.code === '01')) {
      const teams = res.data || [];
      logger.debug(`Found ${teams.length} team(s) for business`, { teamsCount: teams.length });
      return teams;
    }

    logger.error('Failed to fetch teams', { message: res?.message || 'Unknown error' });
    throw new Error((res && res.message) || 'Failed to fetch teams');
  },

  async updateTeam(businessId, teamId, teamData) {
    if (!String(businessId || '').trim()) {throw new Error('Business ID is required');}
    if (!String(teamId || '').trim()) {throw new Error('Team ID is required');}

    const body = {};
    if (teamData.name !== undefined) {body.name = String(teamData.name || '').trim();}
    if (teamData.menus !== undefined) {body.menus = teamData.menus;}

    const res = await apiRequest(`/api/team/${teamId}/update`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });

    if (res && (res.code === '01' || res.code === '00')) {return res.data || res;}
    throw new Error((res && res.message) || 'Failed to update team');
  },


  async addTeamMember(teamId, memberData) {
    logger.debug('Adding team member', { memberData, teamId });
    if (!String(teamId || '').trim()) {throw new Error('Team ID is required');}

    const fullName = memberData.full_name || memberData.name;
    const email = memberData.email;
    const phone = memberData.phone || memberData.phoneNumber;

    if (!fullName || !email || !phone) {
      throw new Error('full_name (or name), email and phone (or phoneNumber) are required');
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(String(email).trim())) {throw new Error('Valid email is required');}

    const body = {
      full_name: String(fullName).trim(),
      email: String(email).trim(),
      phone: phone ? cleanNumberForBackend(String(phone).trim()) : String(phone).trim(),
    };

    const res = await apiRequest(`/api/team/${teamId}/add-member`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });

    if (res && (res.code === '01' || res.code === '00')) {return res.data || res;}
    throw new Error((res && res.message) || 'Failed to add team member');
  },

  async getTeamMembers(teamId) {
    if (!String(teamId || '').trim()) {throw new Error('Team ID is required');}

    const res = await apiRequest(`/api/team/${teamId}/members`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
    });

    if (res && (res.code === '00' || res.code === '01')) {return res.data || [];}
    throw new Error((res && res.message) || 'Failed to fetch team members');
  },

  async removeTeamMember(teamId, memberId) {
    if (!String(teamId || '').trim()) {throw new Error('Team ID is required');}
    if (!String(memberId || '').trim()) {throw new Error('Member ID is required');}

    logger.debug('Removing team member', { teamId, memberId });

    const res = await apiRequest(`/api/team/${teamId}/remove-member/${memberId}`, {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
    });

    logger.debug('Remove member response', { response: res });

    if (res && (res.code === '01' || res.code === '00')) {return res.data || res;}
    throw new Error((res && res.message) || 'Failed to remove team member');
  },

  async getTeamDetails(teamId) {
    if (!String(teamId || '').trim()) {throw new Error('Team ID is required');}

    const res = await apiRequest(`/api/team/${teamId}/teamdetails`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
    });

    logger.debug('getTeamDetails response', { response: res });

    if (res && (res.code === '00' || res.code === '01')) {return res.data || res;}
    throw new Error((res && res.message) || 'Failed to fetch team details');
  },


  async getUserTeamPermissions(userId, businessId) {
    if (!String(userId || '').trim()) {throw new Error('User ID is required');}
    if (!String(businessId || '').trim()) {throw new Error('Business ID is required');}

    // Get user teams first, then aggregate permissions
    const userTeams = await this.getUserTeams(userId, businessId);

    // Aggregate all permissions from user's teams
    const allPermissions = new Set();
    if (Array.isArray(userTeams) && userTeams.length > 0) {
      userTeams.forEach(team => {
        const teamPerms = team.menus || team.page_access || [];
        if (Array.isArray(teamPerms)) {
          teamPerms.forEach(perm => allPermissions.add(perm));
        }
      });
    }

    return Array.from(allPermissions);
  },

  async getUserTeams(userId, businessId) {
    if (!String(userId || '').trim()) {throw new Error('User ID is required');}
    if (!String(businessId || '').trim()) {throw new Error('Business ID is required');}

    logger.debug('getUserTeams called', { userId, businessId });

    try {
      // Get all teams for the business
      const allTeams = await this.getTeams(businessId);
      logger.debug('All teams for business', { allTeams });

      if (!Array.isArray(allTeams) || allTeams.length === 0) {
        logger.warn('No teams found for business', { businessId });
        return [];
      }

      // For each team, check if the user is a member
      const userTeams = [];

      for (const team of allTeams) {
        try {
          // Get members for this team
          const members = await this.getTeamMembers(team.id);
          logger.debug(`Members for team ${team.name}`, { teamId: team.id, teamName: team.name, members });

          // Check if user is a member of this team
          if (Array.isArray(members)) {
            const isMember = members.some(member => {
              const memberUserId = member.user_id || member.userId || member.users?.id || member.id;
              const matches = String(memberUserId) === String(userId);
              logger.debug('Checking member', {
                memberUserId,
                userId,
                matches,
                memberStructure: Object.keys(member)
              });
              return matches;
            });

            if (isMember) {
              logger.debug(`User is a member of team: ${team.name}`, { teamName: team.name });
              userTeams.push(team);
            } else {
              logger.debug(`User is NOT a member of team: ${team.name}`, { teamName: team.name });
            }
          }
        } catch (error) {
          logger.error(`Failed to get members for team ${team.id}`, { error, teamId: team.id });
          // Continue to next team even if this one fails
        }
      }

      logger.debug('User teams found', { userTeams });
      return userTeams;
    } catch (error) {
      logger.error('Failed to fetch user teams', { error });
      throw new Error((error && error.message) || 'Failed to fetch user teams');
    }
  }
};

export const teamService = _teamService;
export default _teamService;
