/**
 * Business Accounts Service
 * 
 * Manages settlement accounts for business users including bank accounts
 * and Mobile Money accounts. Handles account creation, retrieval, and
 * business ID resolution from various storage locations.
 */

import apiRequest from '@/shared/services/apiClient.js';
import { tokenService } from '@/features/auth/services/tokenService.js';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import logger from '@/shared/utils/logger.js';

function resolveBusinessId(explicitBusinessId) {
  if (explicitBusinessId) {return explicitBusinessId;}
  try {
    const user = tokenService.getUserData();
    return (
      user?.businessId ||
      user?.business_id ||
      user?.business?.id ||
      (() => {
        try {
          const fromStorage = localStorage.getItem('businessId');
          if (fromStorage && fromStorage !== 'undefined' && fromStorage !== 'null') {return fromStorage;}
        } catch (_e) {}
        return user?.id;
      })()
    );
  } catch (_e) {
    return null;
  }
}

export const businessAccountsService = {
  async getAccounts(businessId) {
    const id = resolveBusinessId(businessId);
    if (!id) {throw new Error('Missing business ID');}
    
    const token = tokenService.getAccessToken();
    if (!token) {
      throw new Error('Authentication required. Please log in again.');
    }
    
    const url = `/api/auth/business/${id}/accounts`;
    logger.debug('[businessAccountsService] GET accounts', { businessId: id, url });
    
    try {
      const resp = await apiRequest(url, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      return resp?.data || [];
    } catch (error) {
      logger.error('Failed to fetch accounts', { error });
      throw error;
    }
  },

  async addBankAccount(businessId, account) {
    const id = resolveBusinessId(businessId);
    if (!id) {throw new Error('Missing business ID');}

    // Ensure date fields are properly formatted as ISO strings
    // The backend expects ISO date strings, not Date objects
    let formattedOpenedDate = account.openedDate || null;
    
    if (formattedOpenedDate) {
      // If it's already a string in ISO format, keep it
      if (typeof formattedOpenedDate === 'string' && formattedOpenedDate.includes('T')) {
        // Already in ISO format
      }
      // If it's a Date object, convert to ISO string
      else if (formattedOpenedDate instanceof Date) {
        try {
          formattedOpenedDate = formattedOpenedDate.toISOString();
        } catch (e) {
          logger.warn('Failed to convert Date to ISO string', { formattedOpenedDate, error: e });
          formattedOpenedDate = null;
        }
      }
      // If it's a string in YYYY-MM-DD format, convert to ISO
      else if (typeof formattedOpenedDate === 'string') {
        try {
          const date = new Date(formattedOpenedDate + 'T00:00:00.000Z');
          if (!isNaN(date.getTime())) {
            try {
              formattedOpenedDate = date.toISOString();
            } catch (e) {
              logger.warn('Failed to convert date to ISO string', { formattedOpenedDate, error: e });
              formattedOpenedDate = null;
            }
          } else {
            formattedOpenedDate = null;
          }
        } catch (e) {
          logger.warn('Invalid date format for opened_date', { formattedOpenedDate });
          formattedOpenedDate = null;
        }
      }
    }

    const payload = {
      account_type: 'bank',
      account_number: account.accountNumber ? cleanNumberForBackend(account.accountNumber) : account.accountNumber,
      account_holder_name: account.accountHolderName,
      bank_name: account.bankName,
      swift_bic: account.swiftCode || null,
      account_category: account.accountType || 'current',
      opened_date: formattedOpenedDate,
    };

    const url = `/api/auth/business/${id}/accounts`;
    logger.debug('[businessAccountsService] POST add bank account', { businessId: id, url, payload });
    return await apiRequest(url, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
  },

  async addMomoAccount(businessId, momo) {
    const id = resolveBusinessId(businessId);
    if (!id) {throw new Error('Missing business ID');}
    const payload = {
      account_type: 'momo',
      provider: momo.provider,
      phone: momo.phone ? cleanNumberForBackend(momo.phone) : momo.phone,
      account_holder_name: momo.accountHolderName,
    };
    const url = `/api/auth/business/${id}/accounts`;
    logger.debug('[businessAccountsService] POST add momo account', { businessId: id, url, payload });
    return await apiRequest(url, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
  },
};

export default businessAccountsService;
