/**
 * API Service
 * 
 * Handles API key generation and retrieval for business users. Provides
 * functionality to generate API credentials using email and password
 * authentication, and retrieve existing API keys.
 */

import { apiRequest } from '@/shared/services/apiClient.js';
import { tokenService } from '@/features/auth/services';
import { logger } from '@/shared/utils/logger.js';

export const apiService = {
  /**
   * Generate API credentials (app_id and app_secret)
   * Uses business-specific endpoint for business users, individual endpoint for individuals
   * @returns {Promise} API response with credentials
   */
  async generateKey() {
    const businessId = this.getBusinessId();
    
    if (businessId) {
      // Business user - use business-specific endpoint
      return await apiRequest(`/auth/business/${businessId}/create-api-credentials`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });
    } else {
      // Individual user - use individual endpoint
      return await apiRequest('/auth/create-api-credentials', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });
    }
  },

  /**
   * Get all API credentials for the authenticated user
   * Uses SAME endpoint for both business users and individuals
   * Only status check endpoints are different between user types
   * @returns {Promise} API response with list of credentials
   */
  async getApiKeys() {
    // Both customers and businesses use the same endpoint for getting credentials
    return await apiRequest('/auth/profile/api-credentials', {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      },
    });
  },

  /**
   * Check API credential status
   * Uses business-specific endpoint for business users, individual endpoint for individuals
   * @returns {Promise} API response with status
   */
  async checkCredentialStatus() {
    const businessId = this.getBusinessId();
    
    if (businessId) {
      // Business user - use business-specific endpoint
      return await apiRequest(`/auth/business/${businessId}/check-api-credentials`, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
        },
      });
    } else {
      // Individual user - use individual endpoint
      return await apiRequest('/auth/check-api-credential-status', {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
        },
      });
    }
  },

  /**
   * Helper method to get business ID for business users
   * @returns {string|null} Business ID or null for individual users
   */
  getBusinessId() {
    try {
      const userData = tokenService.getUserData();
      if (!userData) return null;

      const userType = tokenService.getUserType();
      const isBusinessContact = userType === 'business_contact' || userType === 'business';

      if (isBusinessContact) {
        return userData?.businesses?.[0]?.id ||
               userData?.business?.id ||
               userData?.business_id ||
               userData?.businessId ||
               localStorage.getItem('businessId') ||
               null;
      }

      return null;
    } catch (error) {
      logger.error('Error getting business ID:', error);
      return null;
    }
  },

  /**
   * Revoke/Delete an API credential
   * @param {string} credentialId - The ID of the credential to revoke
   * @returns {Promise} API response
   */
  async revokeApiKey(credentialId) {
    // Check if DELETE endpoint exists in Postman collection
    // For now, using the same endpoint with DELETE method
    return await apiRequest(`/auth/profile/api-credentials/${credentialId}`, {
      method: 'DELETE',
      headers: {
        'Content-Type': 'application/json',
      },
    });
  },
};