/**
 * Contact Person Service
 * 
 * Handles business contact person profile operations including retrieving
 * and updating personal information for business contact users.
 */

import { apiRequest } from '@/shared/services/apiClient.js';

export const contactPersonService = {
  async getPersonalInfo() {
    const data = await apiRequest('/api/auth/profile/contact-person/personal-info', {
      method: 'GET',
    });

    return data;
  },

  async updatePersonalInfo(profileData) {
    // Build request body with available fields
    const requestBody = {
      ...(profileData.dob && { dob: profileData.dob }),
      ...(profileData.birth_place && { birth_place: profileData.birth_place }),
      ...(profileData.country && { country: profileData.country }),
      ...(profileData.city && { city: profileData.city }),
      ...(profileData.area && { area: profileData.area }),
      ...(profileData.residential_address && { residential_address: profileData.residential_address }),
      ...(profileData.digital_address && { digital_address: profileData.digital_address }),
    };

    const updateData = await apiRequest('/api/auth/profile/contact-person/personal-info', {
      method: 'PUT',
      body: JSON.stringify(requestBody),
    });

    return updateData;
  },
};

export default contactPersonService;
